 87	char quantize4bit(double D,double x)
 88	{
 89	
 90	  double qxd;
 91	
 92	  qxd = floor(x/D);
 93	  //  printf("x=%f,qxd=%f\n",x,qxd);
 94	
 95	  if (qxd <= -8)
 96	    qxd = -8;
 97	  else if (qxd > 7)
 98	    qxd = 7;
 99	
100	  return((char)qxd);
101	}
