103	char quantize(double D,double x,unsigned char B)
104	{
105	
106	  double qxd;
107	  char maxlev;
108	
109	  qxd = floor(x/D);
110	  //  printf("x=%f,qxd=%f\n",x,qxd);
111	
112	  maxlev = 1<<(B-1);
113	
114	  if (qxd <= -maxlev)
115	    qxd = -maxlev;
116	  else if (qxd >= maxlev)
117	    qxd = maxlev-1;
118	
119	  return((char)qxd);
120	}
